import React, { useState, useEffect } from 'react';
import {
  Dialog,
  DialogTitle,
  DialogContent,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Paper,
  Typography,
  Box,
  IconButton,
  Tooltip,
  CircularProgress,
  Alert
} from '@mui/material';
import {
  Close,
  Refresh
} from '@mui/icons-material';
import dashboardService from '../../services/dashboardService';

const FinishedOperationsModal = ({ open, onClose, hideValues = false }) => {
  const [positions, setPositions] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [refreshing, setRefreshing] = useState(false);

  const loadFinishedPositions = async () => {
    try {
      setLoading(true);
      setError('');
      const response = await dashboardService.getFinishedPositions();
      console.log('Resposta do backend:', response);

      if (response.success && Array.isArray(response.positions)) {
        setPositions(response.positions);
      } else {
        setError(response.message || 'Erro ao carregar operações');
      }
    } catch (err) {
      console.error('Erro ao carregar operações finalizadas:', err);
      setError('Erro ao carregar operações');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (open) {
      loadFinishedPositions();
    }
  }, [open]);

  const handleRefresh = async () => {
    setRefreshing(true);
    await loadFinishedPositions();
    setRefreshing(false);
  };

  const formatDateTime = (timestamp) => {
    if (!timestamp) return '-';
    const date = new Date(parseInt(timestamp));
    return date.toLocaleString();
  };

  const formatValue = (value) => {
    if (value === undefined || value === null || value === '') return '-';
    const numValue = parseFloat(value);
    return numValue.toFixed(4);
  };

  return (
    <Dialog
      open={open}
      onClose={onClose}
      maxWidth="lg"
      fullWidth
    >
      <DialogTitle>
        <Box display="flex" justifyContent="space-between" alignItems="center">
          <Typography variant="h6">Operações Finalizadas</Typography>
          <Box>
            <Tooltip title="Atualizar">
              <IconButton onClick={handleRefresh} disabled={refreshing}>
                <Refresh />
              </IconButton>
            </Tooltip>
            <Tooltip title="Fechar">
              <IconButton onClick={onClose}>
                <Close />
              </IconButton>
            </Tooltip>
          </Box>
        </Box>
      </DialogTitle>

      <DialogContent>
        {loading ? (
          <Box display="flex" justifyContent="center" p={3}>
            <CircularProgress />
          </Box>
        ) : error ? (
          <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>
        ) : positions.length === 0 ? (
          <Alert severity="info">Nenhuma operação finalizada encontrada</Alert>
        ) : (
          <TableContainer component={Paper}>
            <Table size="small">
              <TableHead>
                <TableRow>
                  <TableCell>Par</TableCell>
                  <TableCell>Lado</TableCell>
                  <TableCell>Tamanho</TableCell>
                  <TableCell>Alavancagem</TableCell>
                  <TableCell>Preço Entrada</TableCell>
                  <TableCell>Preço Saída</TableCell>
                  <TableCell>Take Profit</TableCell>
                  <TableCell>Stop Loss</TableCell>
                  <TableCell>Lucro/Prejuízo</TableCell>
                  <TableCell>Taxa</TableCell>
                  <TableCell>Data Abertura</TableCell>
                  <TableCell>Data Fechamento</TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {positions.map((position, index) => (
                  <TableRow key={`${position.symbol}-${position.cTime}-${index}`}>
                    <TableCell>{position.symbol}</TableCell>
                    <TableCell>
                      <Box
                        component="span"
                        sx={{
                          color: position.holdSide?.toLowerCase() === 'long' ? 'success.main' : 'error.main',
                          fontWeight: 'bold'
                        }}
                      >
                        {position.holdSide?.toUpperCase() || '-'}
                      </Box>
                    </TableCell>
                    <TableCell>{formatValue(position.openTotalPos)}</TableCell>
                    <TableCell>{position.leverage || '-'}x</TableCell>
                    <TableCell>{formatValue(position.openPriceAvg)}</TableCell>
                    <TableCell>{formatValue(position.closePriceAvg)}</TableCell>
                    <TableCell>{formatValue(position.takeProfit)}</TableCell>
                    <TableCell>{formatValue(position.stopLoss)}</TableCell>
                    <TableCell>
                      <Box
                        component="span"
                        sx={{
                          color: parseFloat(position.profit) >= 0 ? 'success.main' : 'error.main',
                          fontWeight: 'bold'
                        }}
                      >
                        {hideValues ? '***' : formatValue(position.profit)}
                      </Box>
                    </TableCell>
                    <TableCell>{hideValues ? '***' : formatValue(position.totalFee)}</TableCell>
                    <TableCell>{formatDateTime(position.cTime)}</TableCell>
                    <TableCell>{formatDateTime(position.uTime)}</TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </TableContainer>
        )}
      </DialogContent>
    </Dialog>
  );
};

export default FinishedOperationsModal;
